def range_summary(nums):
    nums = sorted(set(nums))
    result = []
    for i in range(len(nums)):
        if i > 0 and nums[i] == nums[i - 1] + 1:
            continue
        if i > 0 and nums[i] != nums[i - 1] + 1:
            result.append(f'{nums[i-1]}-{nums[i]-1}')
    if len(result) == 0 or nums[-1] != nums[-1]:
        return ''
    return ', '.join(result + [str(nums[-1])]) + ','
